// ── Lookup ──────────────────────────────────────────────────────────

type IntensityKey = "low" | "medium" | "high"
type SentimentKey = "negative" | "neutral" | "positive"

const TEMPLATES: Record<IntensityKey, Record<SentimentKey, DoodleTemplate>> = {
  low: { negative: LOW_NEGATIVE, neutral: LOW_NEUTRAL, positive: LOW_POSITIVE },
  medium: { negative: MEDIUM_NEGATIVE, neutral: MEDIUM_NEUTRAL, positive: MEDIUM_POSITIVE },
  high: { negative: HIGH_NEGATIVE, neutral: HIGH_NEUTRAL, positive: HIGH_POSITIVE },
}

const INTENSITY_MAP: Record<1 | 2 | 3, IntensityKey> = {
  1: "low",
  2: "medium",
  3: "high",
}

function toSentiment(positiveness: -2 | -1 | 0 | 1 | 2): SentimentKey {
  if (positiveness < 0) return "negative"
  if (positiveness > 0) return "positive"
  return "neutral"
}

export function getTemplate(
  intensity: 1 | 2 | 3,
  positiveness: -2 | -1 | 0 | 1 | 2,
): DoodleTemplate {
  return TEMPLATES[INTENSITY_MAP[intensity]][toSentiment(positiveness)]
}

export type { DoodleTemplate }
